"""
MKT Context Commentary — Genesis chapters 38–40
Run: python3 scripts/zc-context-genesis-38-40.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (prior chapters; merge_comm skips already-present entries)

Key decisions in this range:
- Ch38 is a deliberate structural interrupt between 37 (Joseph sold) and 39 (Joseph in Egypt);
  it focuses on Judah's moral failure and Tamar's counter-claim, positioning Judah's line as
  morally complex before the redemption arc of chs 43-45
- Ch38:v8 levirate duty: pre-dates Deut 25:5-10; the ANE custom predates and is incorporated by
  Mosaic legislation; the commentary notes this as legal background, not Christian typology
- Ch38:v15 zônāh vs. qĕḏēšāh: the terms differ (common prostitute vs. consecrated/shrine
  prostitute); the uncertainty about qĕḏēšāh's exact meaning in ANE practice is flagged
- Ch38:v26 "more righteous than I": treated as a genuine legal-moral verdict, not just
  gracious concession; Tamar's claim was legally correct under levirate obligation
- Ch39 "Tale of Two Brothers" parallel: noted as a known Egyptian narrative type, not as
  direct literary source; the comparison illuminates the cultural plausibility of the episode
- Ch39 cloak motif: the cloak as evidence thread (37→39→44) is a within-Joseph-narrative
  pattern; noted as ANE narrative art, not typology
- Ch40:v19 "lift up your head" wordplay: the identical formula used for restoration (cupbearer)
  and execution (baker) is a documented Hebrew wordplay; flagged explicitly
- Ch40:v20 Pharaoh's birthday: only explicit royal birthday reference in the OT until Mark 6:21
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "38": {
    "1": '<p>"At that time, Judah left his brothers and went down to stay with a man of Adullam named Hirah" — this chapter is deliberately placed between Joseph\'s arrival in Egypt (ch.37) and his service in Potiphar\'s household (ch.39). The interruption shifts focus to Judah, whose descendants will carry the royal and Messianic line. Judah\'s departure from the family — "left his brothers" (<em>wayyērĕḏ</em>, went down) — signals geographic and social separation from the covenant household. Adullam is in the Shephelah, the lowland foothills between Judah\'s later highland territory and the Philistine coast — Canaanite territory.</p>',

    "2": '<p>"Judah met the daughter of a Canaanite man named Shua. He married her and slept with her" — the Canaanite marriage is the exact violation that Isaac and Rebekah feared (26:34-35) and that Isaac explicitly forbade when sending Jacob to Paddan-Aram (28:1). Esau\'s Hittite marriages brought grief to his parents; Judah now follows the same pattern. The woman is never named — identified only as "Shua\'s daughter" (<em>bat-šûaʿ</em>) — a narrative choice that may indicate her peripheral status in the covenant household\'s perspective.</p>',

    "3": '<p>"She became pregnant and gave birth to a son, who was named Er" — three sons are born in rapid succession (vv.3-5), each with a brief birth notice. Er\'s name (ʿēr) is unexplained; it appears to be related to a root meaning "watching" or may simply be a Semitic personal name. The rapid listing of three sons without dwelling on the births reflects the narrative\'s interest in what happens to those sons rather than their arrival.</p>',

    "4": '<p>"She conceived again and gave birth to a son and named him Onan" — the name <em>ʾônān</em> is probably related to the root <em>ʾôn</em> (strength, vigor) or possibly <em>ʾāwen</em> (trouble, sorrow). Like Er, Onan is named without editorial comment at birth; the narrator\'s assessment comes with the levirate episode of v.9. Shua\'s daughter is the one who names Onan, as Leah named her sons in ch.29 — maternal naming was common when the father was absent or disengaged.</p>',

    "5": '<p>"She gave birth to still another son and named him Shelah. It was at Chezib that she gave birth to him" — the note about Chezib\'s location (probably Achzib in the Shephelah, modern Tell el-Beida near Adullam) is unusual; it may explain Judah\'s absence at the birth or mark a separation that Shelah would later inhabit. Shelah (<em>šēlāh</em>, perhaps "request" or a geographic name) becomes the pivot of the chapter\'s legal crisis when Judah refuses to assign him to Tamar (v.11).</p>',

    "6": '<p>"Judah got a wife for Er, his firstborn, and her name was Tamar" — the father\'s selection of his son\'s wife follows standard ANE practice; Er does not choose his own wife. Tamar (<em>tāmār</em>, "palm tree") — a name associated with beauty and height in the OT (cf. 2 Sam 13:1; 14:27) — is introduced without family identification, unlike the patriarchal wives who are carefully sourced from the covenant family. Her origins are unknown; some traditions identify her as Aramean or Canaanite, others as Israelite.</p>',

    "7": '<p>"But Er, Judah\'s firstborn, was wicked in the LORD\'s sight; so the LORD put him to death" — the narrator does not specify Er\'s wickedness, leaving it to summary divine judgment. The brevity — no narrative of the sin, no appeal, immediate death — creates a stark contrast with the extended negotiations that follow. The divine-agency framing ("the LORD put him to death") mirrors the same language used for Onan\'s death in v.10. What the two brothers share is wickedness that attracted divine attention; the specific nature of Er\'s sin is withheld.</p>',

    "8": '<p>"Sleep with your brother\'s wife and fulfill your duty to her as a brother-in-law to raise up offspring for your brother" — the Hebrew term <em>yaḇṓm</em> (to perform the duty of a brother-in-law) is where "levirate" derives — from Latin <em>levir</em> (brother-in-law). The levirate institution required a surviving unmarried brother to marry his dead brother\'s childless widow so that the dead brother\'s name would continue through the offspring. This practice predates and is later formalized in Deut 25:5-10, which also legislates the <em>ḥăliṣāh</em> ceremony for refusal. The custom is attested in Middle Assyrian law as well. Judah\'s instruction to Onan is legally correct under this pre-Mosaic customary law.</p>',

    "9": '<p>"But Onan knew that the child would not be his; so whenever he slept with his brother\'s wife, he spilled his semen on the ground" — Onan\'s sin is specifically the refusal to fulfill the levirate obligation while taking the sexual benefits of the marriage. He sleeps with Tamar (enjoying the marital relationship) but deliberately prevents conception (denying her the offspring she is legally entitled to). The sin is not the sexual act itself but the covetous exploitation of the levirate arrangement: Onan benefits from the marriage while ensuring Tamar produces no heir who would be counted as Er\'s — which would reduce Onan\'s inheritance share. Tamar is the victim of this fraud.</p>',

    "10": '<p>"What he did was wicked in the LORD\'s sight; so the LORD put him to death also" — the parallel with v.7 (Er\'s death) creates a pattern: Judah\'s sons who wrong Tamar die by divine judgment. The reader begins to understand why Judah fears for Shelah. His reasoning (v.11) that Shelah "may die too, just like his brothers" misattributes the cause — the brothers died for their own wickedness, not for being Tamar\'s husband — but the fear is humanly comprehensible given two consecutive deaths of sons in the same family role.</p>',

    "11": '<p>"Live as a widow in your father\'s household until my son Shelah grows up" — the instruction to return to her father\'s house as a widow was a recognized legal status in the ANE: a widow awaiting levirate fulfillment remained under the dead husband\'s family\'s obligation but could temporarily reside with her own family. Judah\'s instruction keeps Tamar legally bound to his household (she cannot remarry) while deferring fulfillment indefinitely. The narrator reveals Judah\'s real motive: "he thought he may die too" — the stalling is self-protective, not procedural. Tamar is essentially trapped: legally obligated to the household but denied the legal remedy she is owed.</p>',

    "12": '<p>"After a long time Judah\'s wife, the daughter of Shua, died" — the death of Shua\'s daughter removes a potential social constraint on Judah\'s behavior; the mourning period provides the temporal context. Timnah (different from the Samson-era Timnah in Judg 14) is probably in the Shephelah near Adullam; sheep shearing was a seasonal festival involving feasting and celebration (cf. Nabal\'s shearing feast in 1 Sam 25:4-8). The communal, celebratory nature of the shearing season is relevant to understanding Tamar\'s plan.</p>',

    "13": '<p>"Your father-in-law is on his way to Timnah to shear his sheep" — Tamar receives advance intelligence of Judah\'s travel plans. The informant is unnamed; the information reaches Tamar in her father\'s house, confirming that she has been waiting. After a long time (v.12) during which Shelah has grown up but she has not been given to him, Tamar understands that Judah has no intention of fulfilling his obligation. Her subsequent plan is a legal remedy pursued through extra-legal means.</p>',

    "14": '<p>"She took off her widow\'s clothes, covered herself with a veil to disguise herself, and then sat down at the entrance to Enaim" — Tamar\'s disguise involves three elements: removing the widow\'s garments (which would identify her immediately), covering her face (which prevents Judah from recognizing her), and positioning herself at a known location on the Timnah road. "Enaim" (<em>ʿênayim</em>) means "two springs" or "eyes"; the toponym may indicate a crossroads or a known site. The narrator provides her motivation explicitly: Shelah had grown up and she had not been given to him. Her action is self-advocacy within the only framework available to her.</p>',

    "15": '<p>"When Judah saw her, he thought she was a prostitute, for she had covered her face" — the irony is precise: the veil that marks a modest woman in some contexts (Rebekah veiling before Isaac in 24:65) here enables a deception. Judah\'s assumption that the veiled woman is a prostitute reflects the context: a woman alone at a roadside, veiled, in proximity to a town — a recognizable type in the ANE. The word used here is <em>zônāh</em> (common prostitute); in v.21, Hirah\'s inquiry uses <em>qĕḏēšāh</em> (a "set-apart" or possibly cult-associated woman), a different term whose exact meaning is debated in scholarship — some older interpretations assumed universal cult prostitution in Canaanite religion, but current scholarship is less certain about the institution\'s extent and uniformity.</p>',

    "16": '<p>"Not realizing that she was his daughter-in-law, he went over to her" — the narrator underlines Judah\'s ignorance of Tamar\'s identity, preventing the episode from being read as intentional incest. The subsequent exchange — Judah proposing sex, Tamar asking for a pledge — is a commercial transaction in ANE terms; the woman negotiates the terms before agreeing. Tamar is acting with full knowledge of who Judah is; Judah is acting without knowledge of who Tamar is.</p>',

    "17": '<p>"I\'ll send you a young goat from my flock" — a kid goat as payment is a credible fee for a roadside encounter; the same commodity appears in Samson\'s encounter with the Timnite woman\'s father (Judg 15:1). Tamar\'s counter-request — a pledge — transforms the transaction from a simple exchange into a legally binding arrangement with collateral. Her choice of collateral (v.18) is what makes the subsequent resolution possible.</p>',

    "18": '<p>"Your seal and its cord, and the staff in your hand" — the cylinder seal or signet ring was in the ANE the most personal legal identifier: in Mesopotamia, cylinder seals were rolled over wet clay to sign contracts; in Canaan, stamp seals served the same function. Surrendering one\'s seal was equivalent to surrendering one\'s legal identity — it could create binding obligations in the owner\'s name. The seal with its cord (on which it hung around the neck) and the staff (a property-ownership marker in some contexts) together constitute an irrefutable identification package. Tamar has chosen collateral that Judah cannot later deny owning.</p>',

    "19": '<p>"After she left, she took off her veil and put on her widow\'s clothes again" — the reversal of disguise is immediate: Tamar resumes her widow\'s status. She has accomplished what she needed: she is pregnant, and she possesses the legal identification that proves the father. The transaction is complete from her perspective, though Judah will not discover its full implications for three months.</p>',

    "20": '<p>"Meanwhile Judah sent the young goat by his friend the Adullamite in order to get his pledge back" — Judah attempts to recover his seal, cord, and staff by sending Hirah with the agreed payment. The attempt to retrieve the pledge is not merely practical but also reputational: if the pledge stays with the woman indefinitely, it creates an ongoing record of the encounter. The failure to find the woman leaves the identification objects in Tamar\'s possession.</p>',

    "21": '<p>"Where is the shrine prostitute who was beside the road at Enaim?" — Hirah\'s inquiry uses <em>qĕḏēšāh</em> (from the root <em>qāḏaš</em>, to be holy/set apart), a term associated in some OT texts with religious prostitution (Deut 23:17; Hos 4:14) but whose precise reference is debated. The locals\' response — "there hasn\'t been any shrine prostitute here" — is factually correct from their perspective: what they saw (or didn\'t see) at Enaim was an ordinary traveler, not a recognized cult functionary. The community\'s categorical denial suggests Hirah is looking for a known category of person that the Enaim community does not recognize as present.</p>',

    "22": '<p>"I didn\'t find her. Besides, the men who lived there said, \'There hasn\'t been any shrine prostitute here\'" — Hirah\'s report includes both his own failure and the community\'s testimony. The double confirmation — I didn\'t find her; they say she wasn\'t there — strengthens the legal position: Judah sent the payment, made reasonable effort to recover the pledge, and has witnesses that no such person was found. This matters for the subsequent legal proceeding: Judah can argue he made his payment.</p>',

    "23": '<p>"Let her keep what she has, or we will become a laughingstock" — Judah\'s concern is reputational: if he continues searching and the story becomes public, the shame of having solicited a prostitute who then vanished with his seal will damage him more than losing the pledge. "Laughingstock" (<em>lābûz</em>, to become an object of contempt) signals the honor-shame calculus: better to quietly absorb the loss than publicize the incident. Judah chooses reputation management over recovering his identifying documents — which remain with Tamar.</p>',

    "24": '<p>"About three months later Judah was told, \'Your daughter-in-law Tamar is guilty of prostitution, and as a result she is now pregnant\'" — the three months are the minimum time for a pregnancy to become publicly visible in the ancient world. The news reaches Judah framed as Tamar\'s guilt: she is his daughter-in-law (still legally bound to his household, awaiting levirate fulfillment), and pregnancy outside that arrangement is legally equivalent to adultery. Judah\'s sentence — "have her burned to death" — is consistent with the penalty for a priest\'s daughter who becomes a prostitute (Lev 21:9), though burning rather than stoning suggests older customary law in the patriarchal period.</p>',

    "25": '<p>"As she was being brought out, she sent a message to her father-in-law. \'I am pregnant by the man who owns these\'" — Tamar times her revelation for the moment of maximum dramatic and legal force: as she is being brought out for execution. She does not accuse Judah verbally but presents the physical evidence and invites recognition. The formulation "the man who owns these" invites Judah himself to make the identification rather than being accused by others — a form of legal theater that preserves his ability to respond with dignity and gives him the option to recognize or deny.</p>',

    "26": '<p>"Judah recognized them and said, \'She is more righteous than I, since I wouldn\'t give her to my son Shelah\'" — <em>ṣāḏĕqāh mimmennî</em> (she is more in the right than I am) is Judah\'s legal verdict on his own case. The acknowledgment is not merely moral graciousness but a formal legal finding: Tamar\'s claim was correct (she was entitled to levirate fulfillment through Shelah), his withholding was a violation of that obligation, and her method of obtaining what was owed her — though unorthodox — was justified by his prior injustice. This self-verdict from the patriarch of Judah\'s line is one of the OT\'s more striking moments of accountability. Gen 49:8-12 will give Judah the preeminent tribal blessing; the path there goes through this admission.</p>',

    "27": '<p>"When the time came for her to give birth, there were twin boys in her womb" — the birth of twins echoes the Genesis pattern: Jacob and Esau (ch.25), and now Perez and Zerah. In each case, the twin birth involves a reversal or inversion of expected birth order. The midwife\'s attempt to mark the firstborn (v.28) sets up the same kind of reversal that shaped Jacob\'s story.</p>',

    "28": '<p>"The midwife took a scarlet thread and tied it on his wrist and said, \'This one came out first\'" — the scarlet thread as a birth marker for the firstborn anticipates later uses of scarlet in the OT: Rahab\'s scarlet cord marks her household for protection (Josh 2:18-21) in what many interpreters read as a sign-parallel. Here the function is legal and practical: the midwife is creating a witness-marker for firstborn status, which determined inheritance rights. The thread is visible testimony to a contested birth order.</p>',

    "29": '<p>"But when he drew back his hand, his brother came out, and she said, \'So this is how you have broken out!\' And he was named Perez" — <em>pereṣ</em> means "breach" or "breaking out" — named for the manner of birth. The midwife\'s exclamation is surprise at the reversal: the hand-first appearance established Zerah as the firstborn, but Perez physically precedes him out of the womb. The birth-order reversal is consistent with Genesis\'s recurring theme that divine purposes bypass the expected order of primogeniture (Ishmael/Isaac; Esau/Jacob; Manasseh/Ephraim). Perez becomes the ancestor of the Davidic royal line: his descendants are listed in Ruth 4:18-22, culminating in David.</p>',

    "30": '<p>"Then his brother, who had the scarlet thread on his wrist, came out. And he was named Zerah" — <em>zeraḥ</em> means "shining" or "rising" (as of the sun or light); possibly related to the root meaning to scatter or spread. Zerah, despite having his firstborn status displaced by Perez\'s breakthrough birth, founds a sub-clan within Judah (Num 26:20); the Zarhites appear in later tribal lists (Josh 7:17-18, where Achan is identified as Zerah\'s descendant). Both twins become tribal progenitors, but Perez\'s line carries the royal inheritance.</p>',
  },
  "39": {
    "1": '<p>"Potiphar, an Egyptian who was one of Pharaoh\'s officials, the captain of the guard, bought him from the Ishmaelites who had taken him there" — the title "captain of the guard" (<em>śar haṭṭabbāḥîm</em>, chief of the slaughterers) designates the head of the palace guard or executioner corps. The word <em>ṭabbāḥ</em> (literally, slaughterer/cook) refers in the ANE context to the executioner corps who were also responsible for royal food preparation — a combination of roles that gave the position access to both the king\'s body and his table. Egyptian parallels include the "chief of the bodyguard" title attested in New Kingdom texts. Potiphar\'s name (<em>pôṭîpar</em>) is probably the Hebrew rendering of an Egyptian name meaning "he whom Re gave" — the theophoric element pointing to the sun deity Ra.</p>',

    "2": '<p>"The LORD was with Joseph so that he prospered, and he lived in the house of his Egyptian master" — the phrase "the LORD was with Joseph" (<em>wayhî YHWH ʾet-yôsēp̄</em>) is the theological thesis of the Joseph narrative. It appears four times in this chapter alone (vv.2, 3, 21, 23) as a refrain interpreting all of Joseph\'s circumstances — including the bad ones — through divine accompaniment. In ANE religious thinking, a deity\'s "presence" or "favor" with a person was recognized through observable outcomes: prosperity, success, and others\' recognition. The Egyptian master will recognize YHWH\'s presence through Joseph\'s results (v.3).</p>',

    "3": '<p>"When his master saw that the LORD was with him and that the LORD gave him success in everything he did" — Potiphar, a polytheist, recognizes Joseph\'s God through the evidence of Joseph\'s success. The narrator does not indicate how Potiphar knows which deity is responsible — whether Joseph explains it or whether Potiphar simply attributes Joseph\'s unusual competence to divine favor in general ANE terms. Either way, the Egyptian master\'s recognition of YHWH is a recurring element: a non-Israelite recognizing the God of Israel through the lives of his covenant people (cf. Rahab in Josh 2:9-11; Ruth\'s declaration in Ruth 1:16).</p>',

    "4": '<p>"Joseph found favor in his eyes and became his attendant. Potiphar put him in charge of his household, and he entrusted to his care everything he owned" — the role of household steward or major-domo was the highest domestic position available to a slave in the ANE. Egyptian administrative records from the Middle Kingdom and Second Intermediate Period (ca. 2000-1600 BCE) document foreign slaves rising to senior household management positions; tomb paintings and administrative papyri show foreigners — Canaanites, Nubians, Syrians — in managerial roles in elite Egyptian households. The historical background is consistent with the period traditionally associated with the Joseph narrative.</p>',

    "5": '<p>"The LORD blessed the household of the Egyptian because of Joseph" — the blessing transferred to the surrounding household through Joseph echoes the pattern of Genesis 12:3 ("all peoples on earth will be blessed through you"). The specific beneficiary of YHWH\'s blessing here is a pagan Egyptian official — a preview of the broader blessing pattern that will culminate in Joseph sustaining all of Egypt and surrounding nations during the famine. The blessing "both in the house and in the field" covers the totality of Potiphar\'s economic interests.</p>',

    "6": '<p>"Joseph was well-built and handsome" — the same phrase used to describe Rachel (29:17: "lovely in form and beautiful"). Physical beauty in the OT narratives is regularly a marker for narrative significance and often triggers narrative complications: David\'s beauty attracts Saul\'s attention and Bathsheba\'s situation; Absalom\'s beauty is noted before his political ambition. Joseph\'s physical appearance immediately precedes the seduction attempt, establishing the causal context. The narrator withholds the seduction setup until after establishing that Potiphar trusts Joseph completely — the simultaneous elevation of Joseph and introduction of his attractiveness sets up the crisis.</p>',

    "7": '<p>"After a while his master\'s wife took notice of Joseph and said, \'Come to bed with me!\'" — the episode has a parallel in the Egyptian "Tale of Two Brothers" (Papyrus D\'Orbiney, ca. 13th century BCE), in which a younger brother named Bata refuses his older brother Anubis\'s wife\'s sexual advances and is falsely accused of assault. The parallel does not prove direct literary dependence; rather, it demonstrates that the narrative type — false accusation by a woman rejected in a seduction attempt — was a known story pattern in Egyptian culture that Joseph\'s audience may have recognized. The woman\'s directness is striking: no pretense or courtship, simply a command.</p>',

    "8": '<p>"But he refused" — Joseph\'s resistance is immediate. His explanation is multi-layered: first, loyalty to Potiphar ("my master does not concern himself with anything in the house; everything he owns he has entrusted to my care") — a business/stewardship argument; then a boundary argument ("No one is greater in this house than I am; my master has withheld nothing from me except you") — a limit defined by Potiphar\'s marriage rights; then a covenant argument (v.9: "How then could I do such a wicked thing and sin against God?"). The three-tier reasoning moves from social obligation to legal boundary to theological principle.</p>',

    "9": '<p>"How then could I do such a wicked thing and sin against God?" — Joseph\'s climactic argument frames adultery not primarily as an offense against Potiphar but as sin against God (<em>ʾĕlōhîm</em>). This is remarkable in context: Potiphar is an Egyptian, YHWH is not Potiphar\'s God, and no Mosaic legislation yet exists to frame adultery as a divine prohibition. Joseph\'s appeal to a theological rather than merely social or legal standard elevates the refusal beyond prudential calculation. David will use the same frame in Ps 51:4: "Against you, you only, have I sinned" — though in David\'s case the sin was actual, not resisted.</p>',

    "10": '<p>"She spoke to Joseph day after day" — the repeated solicitation over time demonstrates that Joseph\'s resistance was not situational but principled. The phrase "he refused to go to bed with her or even to be with her" is the strongest possible avoidance: not just refusing the specific act but withdrawing proximity that could create opportunity. The daily repetition establishes that this is not a one-time crisis but a sustained pattern of temptation and resistance.</p>',

    "11": '<p>"One day he went into the house to attend to his duties, and none of the household servants was inside" — the empty house is the occasion that the woman exploits. Joseph\'s presence is professional (attending to his duties), not sought-after; the absence of witnesses removes the social deterrent. The situation is the ANE legal equivalent of a honey trap: the woman uses the physical circumstance that she has either arranged or recognized as an opportunity.</p>',

    "12": '<p>"She caught him by his cloak and said, \'Come to bed with me!\' But he left his cloak in her hand and ran out of the house" — the cloak (<em>begeḏ</em>, garment) seized and retained becomes the false evidence. This is the second time a garment becomes pivotal evidence in the Joseph narrative: in 37:31-33, the brothers dip Joseph\'s long robe in goat\'s blood as proof of death to show Jacob. Here, the abandoned cloak becomes the proof of assault that Potiphar\'s wife will display. The garment-as-evidence motif runs through the Joseph chapters (37, 39, 44) as a recurring narrative thread.</p>',

    "13": '<p>"When she saw that he had left his cloak in her hand and had run out of the house" — Potiphar\'s wife\'s response is immediate and calculated: she uses the physical evidence before her story can be challenged. Her cry to the household servants (v.14) creates a public record of her accusation before Joseph can offer any counter-narrative. The speed of her response suggests premeditation or rapid opportunism.</p>',

    "14": '<p>"Look, this Hebrew has been brought to us to make sport of us!" — Potiphar\'s wife\'s accusation uses the ethnic/status marker "Hebrew" (<em>ʿiḇrî</em>) to distance Joseph from the household. "Hebrew" in the OT tends to be used by outsiders or in situations emphasizing foreignness and lowly status (cf. Jonah 1:9; Exod 1:15-16). Her framing — "brought to us" — emphasizes his slave status and implies the household was victimized by taking him in. "Make sport of us" (<em>liṣḥaq bānû</em>) — the same root used for Isaac\'s name (<em>ṣāḥaq</em>) and for what Ishmael was doing to Isaac in 21:9 — is an ironic echo.</p>',

    "15": '<p>"When he heard me scream for help, he left his cloak beside me and ran out of the house" — Potiphar\'s wife constructs a coherent false narrative: approach, assault, scream, flight, abandoned garment. The cloak is the physical evidence that makes the account credible; without it, her word against his. With it displayed beside her (v.16), she has a material witness to the encounter that Joseph cannot explain away without access to her and the witnesses she has already briefed.</p>',

    "16": '<p>"She kept his cloak beside her until his master came home" — the cloak on display until Potiphar\'s return is evidence management: she ensures the material proof is visible and fresh. The time between the incident and Potiphar\'s arrival creates a period during which the servants\' accounts have been given, her emotional state has been established, and Joseph has had no opportunity to present a defense.</p>',

    "17": '<p>"That Hebrew slave you brought us came to me to make sport of me" — the accusation is repeated, this time to Potiphar with an added implication: "that you brought us" — subtly blaming Potiphar for the situation. The accusation is socially calibrated: calling Joseph a "Hebrew slave" reasserts his status inferiority; attributing the situation to Potiphar\'s choice to bring him in creates a shared grievance between husband and wife against the slave.</p>',

    "18": '<p>"But as soon as I screamed for help, he left his cloak beside me and ran out of the house" — the identical narrative for the second time establishes the story in Potiphar\'s mind before he can speak with Joseph. The consistency of the account (same details to servants and husband) gives it the appearance of reliability. Whether Potiphar fully believes his wife or suspects but cannot act otherwise without losing face is not resolved by the text.</p>',

    "19": '<p>"When his master heard the story his wife told him, saying, \'This is how your slave treated me,\' he burned with anger" — Potiphar\'s anger is noted but its object is ambiguous in the Hebrew: "he burned with anger" without specifying anger at whom. Some interpreters argue the anger was directed at Joseph; others suggest the anger may have been partly at the whole situation (including his wife\'s behavior). What is notable is that Potiphar does not execute Joseph — which he could have done and which was the expected response to an assault on the master\'s wife in the ANE. Instead, Joseph goes to prison.</p>',

    "20": '<p>"Joseph\'s master took him and put him in prison, the place where the king\'s prisoners were confined" — the royal prison (<em>bêt has-sōhar</em>) is distinct from ordinary imprisonment; <em>sōhar</em> appears only in the Joseph narrative in the OT. Egyptian "prisons" of this period were often labor compounds where offenders worked under supervision; the designation "where the king\'s prisoners were confined" indicates a facility for political detainees and court offenders — placing Joseph in proximity to the court officials whose dreams he will interpret in ch.40. The choice of prison over execution may reflect Potiphar\'s private doubt about his wife\'s account, or simply that enslaved people\'s lives were commodities he chose to preserve.</p>',

    "21": '<p>"The LORD was with him; he showed him unfailing love (<em>ḥeseḏ</em>) and granted him favor in the eyes of the prison warden" — the ḥeseḏ vocabulary — covenant faithfulness, steadfast love — applied to Joseph\'s prison situation is the same vocabulary used for YHWH\'s covenantal fidelity in the Psalms and the ancestral narratives. Even in prison, Joseph experiences divine ḥeseḏ enacted through practical favor. The pattern of ch.39 repeats at a lower level: as Joseph rose in Potiphar\'s house, so he rises in the prison — "the LORD was with Joseph" functions as the structural backbone of the whole chapter.</p>',

    "22": '<p>"The warden put Joseph in charge of all those held in the prison, and he was made responsible for all that was done there" — the structural parallel with v.4 (Potiphar putting Joseph in charge of his household) is exact: slave → stewardship → comprehensive responsibility. The same pattern that characterized Joseph\'s rise in Potiphar\'s house repeats in the prison. The Joseph narrative uses this recursive structure to demonstrate that Joseph\'s competence and divine favor operate consistently regardless of the social setting: household, prison, ultimately palace.</p>',

    "23": '<p>"The warden paid no attention to anything under Joseph\'s care, because the LORD was with Joseph and gave him success in whatever he did" — the final verse of the chapter closes with the same statement it opened with (v.2-3): the LORD\'s presence producing recognizable success and the superior\'s withdrawal of close oversight. The chapter forms a chiastic structure around the divine-presence refrain: Joseph elevated → tempted → falsely accused → imprisoned → elevated again. In each location, YHWH\'s presence is the constant that makes the elevation possible.</p>',
  },
  "40": {
    "1": '<p>"The cupbearer and the baker of the king of Egypt offended their master, the king of Egypt" — the Hebrew term for cupbearer is <em>mašqeh</em> (one who gives drink), a role with extensive ANE documentation. The cupbearer occupied one of the most trusted positions in any ancient royal court: he controlled direct access to the king\'s drink, making him the primary defense against poisoning. Egyptian, Assyrian, and Babylonian records all document "chief cupbearer" as a major court title with political influence; Nehemiah served as cupbearer to Artaxerxes of Persia (Neh 1:11). The chief baker similarly controlled the king\'s food supply. That both court officials simultaneously offended Pharaoh suggests either a conspiracy allegation or separate incidents; the text does not specify the offense.</p>',

    "2": '<p>"Pharaoh was angry with his two officials, the chief cupbearer and the chief baker" — Pharaoh\'s anger at these two specific officials creates the mechanism that places them in the same prison as Joseph. The judicial detention of court officials while their cases were investigated was standard ANE practice; the officials remain in custody pending Pharaoh\'s final disposition of their cases (v.13, 19). Their status as royal officials — not ordinary prisoners — explains why they are assigned a personal attendant (Joseph, v.4) rather than being integrated into the general prison population.</p>',

    "3": '<p>"He put them in custody in the house of the captain of the guard, in the same prison where Joseph was confined" — "the house of the captain of the guard" identifies the facility as connected to Potiphar\'s domain (39:1 identified Potiphar as "captain of the guard"). Whether Potiphar is still in this role or has been succeeded is unclear, but the prison where Joseph was placed is now confirmed as the facility directly under the guard captain\'s authority — the same household that originally detained Joseph. The confluence of the court officials\' case with Joseph\'s imprisonment is the narrative hinge of the story.</p>',

    "4": '<p>"The captain of the guard assigned them to Joseph, and he attended them" — Joseph\'s role as attendant to the court officials is the practical mechanism that creates the relationship through which the dream interpretations will occur. His position — prisoner serving imprisoned court officials — is the lowest possible social starting point for the contact that will eventually bring him to Pharaoh\'s court. The phrase "after they had been in custody for some time" suggests a period of weeks or months during which the relationship developed before the dreams occurred.</p>',

    "5": '<p>"Each of the two men had a dream the same night, and each dream had a meaning of its own" — the ANE took dreams as divine communication with great seriousness. Egypt had professional dream interpreters and maintained dream interpretation manuals; the Mesopotamian Ziqiqu series catalogued dream symbols and their meanings systematically. The conviction that dreams required interpretation — and that interpretive ability was a gift of the deity rather than mere human skill — is pan-ANE. The detail that the two dreams occurred "the same night" and each had "its own meaning" signals that these are not random psychological events but coordinated divine communications with distinct contents.</p>',

    "6": '<p>"When Joseph came to them the next morning, he saw that they were dejected" — Joseph\'s perceptiveness of the officials\' emotional state is the quality that opens the conversation. A purely task-oriented servant might bring their food and leave; Joseph notices their distress. The ability to read people — already evident in Joseph\'s interpretations throughout his story — is here the quality that leads to the dream conversation. The Hebrew <em>zōʿăpîm</em> (troubled, dejected) indicates visible emotional distress, not just internal anxiety.</p>',

    "7": '<p>"Why do you look so sad today?" — Joseph\'s direct question to Pharaoh\'s officials crosses the social boundary between prisoner-attendant and the high-status officials in his care. The boldness of the question reflects Joseph\'s character throughout Genesis: he does not operate with the passivity one might expect of his circumstances. The parallel in ch.37 is his reporting of his brothers\' misdeeds to Jacob (37:2) — Joseph as an active observer and reporter. Here, the question opens the conversation that will change his life.</p>',

    "8": '<p>"\'We both had dreams, but there is no one to interpret them.\' Then Joseph said to them, \'Do not interpretations belong to God? Tell me your dreams.\'" — Joseph\'s counter to their complaint is the theological claim that directly challenges the Egyptian assumption: interpretation belongs to God (<em>ʾĕlōhîm</em>), not to the professional magicians (<em>ḥarṭummîm</em>) who are unavailable to them in prison. The same counter will appear in 41:16 when Pharaoh credits Joseph with interpretation skill: "It is not in me; God will give Pharaoh a favorable answer." Joseph is not claiming personal interpretive skill but divine access — a claim that will be tested and confirmed in both chapters.</p>',

    "9": '<p>"In my dream I saw a vine in front of me" — the cupbearer\'s dream imagery is drawn from his professional world: vine, branches, blossoming, grapes, Pharaoh\'s cup. The vine is not an unusual Egyptian motif; viticulture is well-attested in Egyptian art and records, and wine was a significant commodity in the royal court. The dream\'s professional imagery — a cupbearer dreams about grapes and Pharaoh\'s cup — is consistent with ANE dream-theory that the deity communicates through symbols accessible to the dreamer\'s experience.</p>',

    "10": '<p>"On the vine were three branches. As soon as it budded, it blossomed, and its clusters ripened into grapes" — the accelerated growth sequence (bud → blossom → ripe clusters in a single dream vision) compresses the growing season into a moment. In ANE dream interpretation, the number of elements (branches) often corresponded to time units (days, months, years). Joseph\'s interpretation in v.12 applies the symbolic substitution method: three branches = three days.</p>',

    "11": '<p>"Pharaoh\'s cup was in my hand, and I took the grapes, squeezed them into Pharaoh\'s cup and put the cup in his hand" — the restoration of the cup to Pharaoh\'s hand is the climactic image: the cupbearer performing his specific professional function for the king. The dream\'s resolution — cup in Pharaoh\'s hand — is the image of restored service. Joseph\'s interpretation reads this as the restoration of the cupbearer\'s office (v.13), reasoning from the professional dream imagery to its literal application.</p>',

    "12": '<p>"The three branches are three days" — the interpretive formula (symbol = time unit) is Joseph\'s method applied without explanation of process. ANE dream interpretation manuals documented similar substitutions; the method was recognized as the craft of interpretation. Joseph applies it with confidence, not uncertainty — he presents the interpretation as given rather than arrived at through deliberation. The speed and directness of the interpretation, attributed to God\'s gift (v.8) rather than personal skill, is what makes it authoritative rather than guesswork.</p>',

    "13": '<p>"Within three days Pharaoh will lift up your head and restore you to your position" — the idiom "lift up your head" (<em>yiśśāʾ parʿōh ʾet-rōʾšĕkhā</em>) means to raise someone\'s status or restore honor — to be recognized by the overlord as worthy. The same idiom appears in Ps 3:3 (YHWH as the one who lifts the head) and in the court language of other ANE texts. The phrase will be grimly reused in v.19 for the baker\'s execution, where the same "lift up your head" formula includes the fatal specification "from off you."</p>',

    "14": '<p>"But when all goes well with you, remember me and show me kindness; mention me to Pharaoh and get me out of this prison" — this is the first time Joseph actively advocates for himself in the narrative. His self-description — "forcibly carried off from the land of the Hebrews, and even here I have done nothing to deserve being put in a dungeon" — is accurate in its essential claims though selectively framed (omitting his brothers\' role, emphasizing injustice). "The land of the Hebrews" (<em>ʾereṣ haʿiḇrîm</em>) is a remarkable ethnic-territorial designation appearing nowhere else in this form, treating the patriarchal territory as already belonging to the Hebrews.</p>',

    "15": '<p>"I was forcibly carried off from the land of the Hebrews, and even here I have done nothing to deserve being put in a dungeon" — the self-advocacy reveals Joseph\'s awareness of his rights. "Forcibly carried off" (<em>gunoḇ gunnōḇtî</em>, I was indeed stolen) uses the intensive form; the second wrong — the false imprisonment — is added as a compound injustice. Joseph is making a legal appeal to the cupbearer: two unjust acts have been done to him, and access to Pharaoh could correct the second. The appeal is careful — he does not ask the cupbearer to act against Potiphar\'s interests but simply to mention his case.</p>',

    "16": '<p>"When the chief baker saw that Joseph had given a favorable interpretation, he said to Joseph, \'I too had a dream\'" — the baker\'s willingness to share his dream was triggered by the cupbearer\'s favorable interpretation. Had Joseph delivered a negative reading first, the baker might have kept his dream private. This sequencing — favorable interpretation first, fatal interpretation second — reflects the narrative\'s dramatic logic: the baker\'s hope is raised before it is destroyed. Joseph does not soften the baker\'s interpretation.</p>',

    "17": '<p>"In the top basket were all kinds of baked goods for Pharaoh, but the birds were eating them out of the basket on my head" — the baker\'s dream is more disturbing in its imagery: food intended for Pharaoh being consumed by birds before delivery represents failure of the baker\'s primary duty. Birds eating from the king\'s food supply was a negative omen in multiple ANE contexts. The baker is not present to deliver the food himself (the passive image of baskets on his head rather than active service of cup to hand) — the dream already lacks the restoration element that characterized the cupbearer\'s dream.</p>',

    "18": '<p>"This is what it means: The three baskets are three days" — Joseph applies the same interpretive formula: three = three days. The parallel opening ("the three baskets are three days," mirroring "the three branches are three days" in v.12) sets up the contrast that follows. The identical formula for two opposite outcomes demonstrates that the meaning is not in the number itself but in the complete dream imagery — the number provides the timing; the other elements provide the nature of the outcome.</p>',

    "19": '<p>"Within three days Pharaoh will lift off your head and impale your body on a pole. And the birds will eat away your flesh" — the grim wordplay: "lift up your head" (<em>yiśśāʾ parʿōh ʾet-rōʾšĕkhā</em>) is the identical formula used for the cupbearer\'s restoration (v.13), but here followed by "from off you" (<em>mēʿālêkhā</em>) — that is, Pharaoh will literally remove his head from his body. Impalement (<em>tālāh</em>, to hang/impale) of executed criminals on poles or stakes was an ANE practice documented in Assyrian reliefs and attested in OT texts (Num 25:4; Deut 21:22); the birds eating the flesh enacts the dream\'s imagery literally. Joseph does not soften the interpretation; he delivers the same directness for a fatal verdict that he applied to the favorable one.</p>',

    "20": '<p>"Now the third day was Pharaoh\'s birthday, and he gave a feast for all his officials" — royal birthday feasts are attested in the ANE: Egyptian festivals, including royal birthdays, were occasions for court assembly and judgment. "He lifted up the heads of the chief cupbearer and the chief baker in the presence of his officials" — the idiom applied simultaneously to both men; the judicial resolution of both cases on the same occasion fulfills Joseph\'s three-day timeline exactly. The birthday feast as the occasion for the judicial resolution connects Egyptian royal celebration with legal adjudication — a combination attested in Herod\'s birthday feast (Mark 6:21) where another head is lifted off.</p>',

    "21": '<p>"He restored the chief cupbearer to his position, so that he once again put the cup into Pharaoh\'s hand" — the fulfillment is exact: the cup in Pharaoh\'s hand, as the cupbearer\'s dream showed and Joseph\'s interpretation predicted. The precision of fulfillment validates Joseph\'s interpretive method and, by implication, the divine source he claimed for it (v.8). The restoration sets up the cupbearer\'s two-year forgetfulness (v.23) and eventual memory (41:9-13) as the mechanism for Joseph\'s introduction to Pharaoh.</p>',

    "22": '<p>"But he impaled the chief baker, just as Joseph had said would happen" — the parallel fulfillment — exact execution of both interpretations on the third day — confirms Joseph as a true interpreter. In the ANE, false prophecy or failed divination had serious consequences; the prophet or diviner\'s credibility was established by fulfillment. Joseph\'s two-for-two accuracy in the same judicial proceeding establishes him as an interpreter whose gift is genuine, preparing the ground for ch.41\'s appeal.</p>',

    "23": '<p>"The chief cupbearer, however, did not remember Joseph; he forgot him" — the double statement (<em>lōʾ zākar...wayyiškāḥēhû</em>, he did not remember...he forgot him) emphasizes the completeness of the forgetting. The forgetting sets up a two-year gap (41:1) before Joseph\'s situation changes — the divine timing mechanism that places Joseph before Pharaoh at precisely the moment when Egypt needs a dream interpreter and a wise administrator. The cupbearer\'s memory and forgetfulness bracket the transition from ch.40 to ch.41: remembered in prison → forgotten for two years → suddenly remembered (41:9: "Today I am reminded of my shortcomings"). The delay is not abandonment; it is preparation for a larger stage.</p>',
  }
}

